#include <stdio.h>

int searchInsert(int *arr, int n, int k) {
    int left = 0, right = n - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == k) return mid;
        else if (arr[mid] > k) right = mid - 1;
        else left = mid + 1;
    }
    return left;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, q;
        scanf("%d %d", &n, &q);
        int arr[1000];
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        for (int i = 0; i < q; ++i) {
            int k;
            scanf("%d", &k);
            printf("%d\n", searchInsert(arr, n, k));
        }
    }
    return 0;
}

