code.Python3:
#!/usr/bin/env python3
import sys

def search_insert(arr, k):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == k:
            return mid
        elif arr[mid] > k:
            right = mid - 1
        else:
            left = mid + 1
    return left

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        q = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        for _ in range(q):
            k = int(next(it))
            out.append(str(search_insert(arr, k)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

